#include <stdio.h>
#include <string.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int aa = 0, bb = 0, ab = 0, ba = 0;
        for (int i = 0; i < N; i++) {
            char s[3];
            scanf("%s", s);
            if (strcmp(s, "aa") == 0) aa++;
            else if (strcmp(s, "bb") == 0) bb++;
            else if (strcmp(s, "ab") == 0) ab++;
            else ba++;
        }
        int min = (ab < ba) ? ab : ba;
        ab -= min;
        ba -= min;
        for (int i = 0; i < min; i++) printf("ab");
        for (int i = 0; i < aa; i++) printf("a");
        for (int i = 0; i < bb; i++) printf("b");
        for (int i = 0; i < aa; i++) printf("a");
        for (int i = 0; i < min; i++) printf("ba");
        printf("\n");
    }
    return 0;
}

