import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int aa = 0, bb = 0, ab = 0, ba = 0;
            for (int i = 0; i < N; i++) {
                String s = sc.next();
                if (s.equals("aa")) aa++;
                else if (s.equals("bb")) bb++;
                else if (s.equals("ab")) ab++;
                else ba++;
            }
            int min = Math.min(ab, ba);
            ab -= min;
            ba -= min;
            for (int i = 0; i < min; i++) System.out.print("ab");
            for (int i = 0; i < aa; i++) System.out.print("a");
            for (int i = 0; i < bb; i++) System.out.print("b");
            for (int i = 0; i < aa; i++) System.out.print("a");
            for (int i = 0; i < min; i++) System.out.print("ba");
            System.out.println();
        }
    }
}

